def main():
    n, m = map(int, input().split())
    graph = defaultdict(list)
    total_disks = 0

    for _ in range(m):
        s1, s2, d = map(int, input().split())
        graph[s1].append((s2, d))
        graph[s2].append((s1, d))
        total_disks += d

    def bfs(start):
        visited = set([start])
        queue = deque([start])
        counts = {start: 0}

        while queue:
            node = queue.popleft()
            for neighbor, disks in graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
                    counts[neighbor] = disks - counts[node]
        return counts

