from fractions import Fraction

def calculate_probability(n, x, y, d):
    # Base case: if the bears are already together
    if abs(x - y) == 0:
        return 1

    # Initialize a 2D array to store the probabilities of the bears being at each location
    prob = [[0.0] * n for _ in range(n)]

    # Initialize the probabilities for the first day
    prob[x-1][y-1] = 1.0

    # Calculate the probability of the bears being together on the first day
    prob_together = 0.0

    # Transition matrix for a single bear
    trans = [[0.0] * n for _ in range(n)]
    for i in range(n):
        if i == 0:
            trans[i][i] = 0.5
            trans[i][i+1] = 0.5
        elif i == n-1:
            trans[i][i] = 0.5
            trans[i][i-1] = 0.5
        else:
            trans[i][i-1] = 0.5
            trans[i][i+1] = 0.5

    # Calculate the probability of the bears being together on each day
    for _ in range(d):
        new_prob = [[0.0] * n for _ in range(n)]
        prob_together_day = 0.0
        for i in range(n):
            for j in range(n):
                for k in range(n):
                    for last_j in range(n):
                        new_prob[k][last_j] += prob[i][j] * trans[i][k] * trans[j][last_j]
                        if k == last_j:
                            prob_together_day += prob[i][j] * trans[i][k] * trans[j][last_j]
        prob = new_prob
        prob_together = 1 - (1 - prob_together) * (1 - prob_together_day)

    return prob_together

def main():
    n, x, y, d = map(int, input().split())
    prob = calculate_probability(n, x, y, d)
    frac = Fraction(prob).limit_denominator()
    print(f'{frac.numerator}/{frac.denominator}')

