from fractions import Fraction
import sys

def read_input():
    return list(map(int, sys.stdin.readline().strip().split()))

def calculate_probability(n, x, y, d):
    if x > y:
        x, y = y, x

    # Base cases
    if y - x == 1:
        prob_meet = Fraction(1, 2)
    else:
        prob_meet = Fraction(0, 1)

    # Transition matrix for one bear
    transition_matrix = [[Fraction(0, 1) for _ in range(n + 1)] for _ in range(n + 1)]
    for i in range(1, n + 1):
        if i == 1:
            transition_matrix[i][1] = Fraction(1, 2)
            transition_matrix[i][2] = Fraction(1, 2)
        elif i == n:
            transition_matrix[i][n - 1] = Fraction(1, 2)
            transition_matrix[i][n] = Fraction(1, 2)
        else:
            transition_matrix[i][i - 1] = Fraction(1, 2)
            transition_matrix[i][i + 1] = Fraction(1, 2)

    # Calculate probability of being at each position after one day for one bear
    prob_x = [Fraction(0, 1)] * (n + 1)
    prob_y = [Fraction(0, 1)] * (n + 1)
    prob_x[x] = Fraction(1, 1)
    prob_y[y] = Fraction(1, 1)

    for _ in range(d):
        new_prob_x = [Fraction(0, 1)] * (n + 1)
        new_prob_y = [Fraction(0, 1)] * (n + 1)
        for i in range(1, n + 1):
            for j in range(1, n + 1):
                new_prob_x[j] += prob_x[i] * transition_matrix[i][j]
                new_prob_y[j] += prob_y[i] * transition_matrix[i][j]
        prob_x = new_prob_x
        prob_y = new_prob_y

        prob_not_meet_today = Fraction(1, 1)
        for i in range(1, n + 1):
            prob_not_meet_today -= prob_x[i] * prob_y[i]
        prob_meet = 1 - (1 - prob_meet) * prob_not_meet_today

    return prob_meet

def main():
    n, x, y, d = read_input()
    probability = calculate_probability(n, x, y, d)
    print(f'{probability.numerator}/{probability.denominator}')

if __name__ == '__main__':
