from fractions import Fraction

def calculate_transition_matrix(n):
    transition_matrix = [[0.0 for _ in range(n)] for _ in range(n)]
    for i in range(n):
        if i == 0:
            transition_matrix[i][0] = 0.5
            transition_matrix[i][1] = 0.5
        elif i == n - 1:
            transition_matrix[i][n - 1] = 0.5
            transition_matrix[i][n - 2] = 0.5
        else:
            transition_matrix[i][i - 1] = 0.5
            transition_matrix[i][i + 1] = 0.5
    return transition_matrix

def multiply_vector_by_matrix(vector, matrix, n):
    result = [0.0 for _ in range(n)]
    for j in range(n):
        for k in range(n):
            result[j] += vector[k] * matrix[k][j]
    return result

def calculate_probability(n, x, y, d):
    transition_matrix = calculate_transition_matrix(n)
    initial_distribution1 = [0.0 for _ in range(n)]
    initial_distribution1[x - 1] = 1.0
    initial_distribution2 = [0.0 for _ in range(n)]
    initial_distribution2[y - 1] = 1.0
    distribution1 = initial_distribution1[:]
    distribution2 = initial_distribution2[:]
    probability_not_meeting = 1.0
    for _ in range(d):
        distribution1 = multiply_vector_by_matrix(distribution1, transition_matrix, n)
        distribution2 = multiply_vector_by_matrix(distribution2, transition_matrix, n)
        probability_not_meeting_today = 1.0
        for j in range(n):
            probability_not_meeting_today -= distribution1[j] * distribution2[j]
        probability_not_meeting *= probability_not_meeting_today
    probability_meeting = 1.0 - probability_not_meeting
    return Fraction(probability_meeting).limit_denominator()

def main():
    n, x, y, d = map(int, input().split())
    probability = calculate_probability(n, x, y, d)
    print(f"{probability.numerator}/{probability.denominator}")

if __name__ == "__main__":
