def leapfrog_encrypt(key, plaintext):
    # Preprocess plaintext
    plaintext = ''.join(filter(str.isalpha, plaintext)).lower()
    n = len(plaintext)

    # Convert key to sequence of numbers
    key = [ord(c) - ord('a') + 2 for c in key]

    # Initialize ciphertext
    ciphertext = ['_'] * n

    # Initialize variables
    i = 0
    direction = 1
    k_index = 0

    while i < n:
        step = key[k_index % len(key)]
        k_index += 1

        # Calculate positions to fill
        positions = []
        if direction == 1:
            j = step - 1
            while j < n:
                if ciphertext[j] == '_':
                    positions.append(j)
                j += step
        else:
            j = n - step
            while j >= 0:
                if ciphertext[j] == '_':
                    positions.append(j)
                j -= step

        # Fill positions
        for pos in positions:
            if i < n:
                ciphertext[pos] = plaintext[i]
                i += 1
            else:
                break

        # Change direction
        direction *= -1

    return ''.join(ciphertext)


def leapfrog_decrypt(key, ciphertext):
    # Convert key to sequence of numbers
    key = [ord(c) - ord('a') + 2 for c in key]

    # Initialize plaintext
    n = len(ciphertext)
    plaintext = [''] * n

    # Initialize variables
    i = 0
    direction = 1
    k_index = 0

    # Mark positions in plaintext
    marked = [False] * n
    while i < n:
        step = key[k_index % len(key)]
        k_index += 1

        # Calculate positions to fill
        positions = []
        if direction == 1:
            j = step - 1
            while j < n:
                if not marked[j]:
                    positions.append(j)
                j += step
        else:
            j = n - step
            while j >= 0:
                if not marked[j]:
                    positions.append(j)
                j -= step

        # Mark positions
        for pos in positions:
            if i < n:
                marked[pos] = True
                i += 1
            else:
                break

        # Change direction
        direction *= -1

    # Reconstruct plaintext
    i = 0
    direction = 1
    k_index = 0
    while i < n:
        step = key[k_index % len(key)]
        k_index += 1

        # Calculate positions to fill
        positions = []
        if direction == 1:
            j = step - 1
            while j < n:
                if marked[j]:
                    positions.append(j)
                j += step
        else:
            j = n - step
            while j >= 0:
                if marked[j]:
                    positions.append(j)
                j -= step

        # Fill positions
        for pos in positions:
            if i < n:
                plaintext[pos] = ciphertext[i]
                i += 1
            else:
                break

        # Change direction
        direction *= -1

    return ''.join(plaintext)


def main():
