import sys
from collections import defaultdict

def read_input():
    return sys.stdin.readline().strip()

def read_ints():
    return map(int, read_input().split())

def main():
    num_problems, num_teams = read_ints()
    problems = set(chr(ord('A') + i) for i in range(num_problems))
    team_initials = [read_input() for _ in range(num_teams)]

    # Count the occurrences of each initial
    initial_counts = defaultdict(int)
    for initials in team_initials:
        valid_initials = ''.join(c for c in initials if c in problems)
        if valid_initials:
            initial_counts[valid_initials] += 1

    # Create a flow network
    source = 'source'
    sink = 'sink'
    graph = defaultdict(dict)
    graph[source] = {initials: count for initials, count in initial_counts.items()}
    for initials in initial_counts:
        for c in set(initials):
            if c not in graph:
                graph[c] = {}
            graph[initials][c] = 1

    for c in problems:
        if c not in graph:
            graph[c] = {}
        graph[c][sink] = 1

    # Compute the maximum flow using the Edmonds-Karp algorithm
    max_flow = 0
    while True:
        parent = {source: None}
        queue = [source]
        while queue and sink not in parent:
            u = queue.pop(0)
            for v, capacity in graph[u].items():
                if capacity > 0 and v not in parent:
                    parent[v] = u
                    queue.append(v)
        if sink not in parent:
            break
        flow = float('inf')
        v = sink
        while v != source:
            u = parent[v]
            flow = min(flow, graph[u][v])
            v = u
        max_flow += flow
        v = sink
        while v != source:
            u = parent[v]
            graph[u][v] -= flow
            if u not in graph[v]:
                graph[v][u] = 0
            graph[v][u] += flow
            v = u

    print(max_flow)

if __name__ == '__main__':
