        unique_letters = set(team)
        valid = True
        for letter in unique_letters:
            if ord(letter) - ord('A') >= p:
                valid = False
                break
        if valid:
            letter_count[frozenset(unique_letters)] += 1

    max_teams = 0
    for r in range(1, len(letter_count) + 1):
        for combination in combinations(letter_count.keys(), r):
            union = set().union(*combination)
            if len(union) == sum(len(s) for s in combination):
                count = sum(letter_count[s] for s in combination)
                max_teams = max(max_teams, count)
    return max_teams

