        if unique_initials:
            initials_count[unique_initials] += 1

    graph = {initials: set() for initials in initials_count}
    for initials1 in initials_count:
        for initials2 in initials_count:
            if initials1 != initials2 and all(c1 != c2 for c1 in initials1 for c2 in initials2):
                graph[initials1].add(initials2)

    max_independent_set = 0
    for mask in range(1 << len(initials_count)):
        subset = [initials for i, initials in enumerate(initials_count) if (mask & (1 << i))]
        if all(initials2 not in graph[initials1] for initials1 in subset for initials2 in subset if initials1 != initials2):
            max_independent_set = max(max_independent_set, sum(initials_count[initials] for initials in subset))

