def get_subsequences(s, k):
    subsequences = set()
    n = len(s)
    def generate_subsequences(current_index, current_subsequence):
        if len(current_subsequence) == k:
            subsequences.add(current_subsequence)
            return
        if current_index >= n:
            return
        for i in range(current_index, n):
            generate_subsequences(i + 1, current_subsequence + s[i])
    generate_subsequences(0, '')
    return subsequences

