        if w == 0 or h == 0:
            return 0

        max_side = min(w, h)
        side_length = 1 << (max_side.bit_length() - 1)

        needed_squares = ((w + side_length - 1) // side_length) * ((h + side_length - 1) // side_length)

        if available_squares[side_length.bit_length() - 1] < needed_squares:
            result = float('inf')
        else:
            new_available_squares = available_squares[:]
            new_available_squares[side_length.bit_length() - 1] -= needed_squares
            result = needed_squares + divide_and_conquer(w % side_length, h % side_length, new_available_squares)
            result = min(result, divide_and_conquer(w, h, new_available_squares) + float('inf')) # Force exploring other paths

            # Try dividing the rectangle differently
            if w >= h:
                divide_w = w // 2
                result = min(result, divide_and_conquer(divide_w, h, available_squares) + divide_and_conquer(w - divide_w, h, available_squares))
            else:
                divide_h = h // 2
                result = min(result, divide_and_conquer(w, divide_h, available_squares) + divide_and_conquer(w, h - divide_h, available_squares))

        memo[(w, h, tuple(available_squares))] = result
        return result

    return divide_and_conquer(W, H, counts)

