def read_ints():
    return map(int, sys.stdin.readline().strip().split())

def main():
    N, M, B = read_ints()
    prices = []
    requirements = []
    solar_energies = []
    for _ in range(N):
        p, r, s = read_ints()
        prices.append(p)
        requirements.append(r)
        solar_energies.append(s)

    buyback_prices = []
    buyback_amounts = []
    for _ in range(N):
        buyback_prices.append(list(read_ints()))
    for _ in range(N):
        buyback_amounts.append(list(read_ints()))

    dp = [[float('inf')] * (B + 1) for _ in range(N + 1)]
    dp[0][0] = 0

    for i in range(N):
        for j in range(B + 1):
            if dp[i][j] == float('inf'):
                continue
            energy = j + solar_energies[i]
            required = requirements[i]
            if energy >= required:
                excess = energy - required
                purchased = 0
                new_energy = excess
                new_cost = dp[i][j]
            else:
                purchased = required - energy
                new_energy = 0
                new_cost = dp[i][j] + prices[i] * purchased

